#include <bits/stdc++.h>
using namespace std;
const int N=1003;
int n,m;
long long a[N],b[N],c[N],dp[N][N][8];
int main(){
	scanf("%d%d",&n,&m);
	for(int i=1;i<=n;i++)
		scanf("%lld%lld%lld",&a[i],&b[i],&c[i]);
	memset(dp,-127,sizeof(dp));
	for(int j=0;j<8;j++)
		dp[0][0][j]=0;
	for(int i=1;i<=n;i++)
		for(int j=0;j<=m;j++)
			for(int k=0;k<8;k++)
				if(j)
					dp[i][j][k]=max(dp[i-1][j][k],dp[i-1][j-1][k]+(k&1?-1:1)*a[i]+(k&2?-1:1)*b[i]+(k&4?-1:1)*c[i]);
				else
					dp[i][j][k]=dp[i-1][j][k];
	long long ans=0;
	for(int i=0;i<8;i++)
		ans=max(ans,dp[n][m][i]);
	printf("%lld",ans);
	return 0;
}
